-- Employees: Table: Employees — people who submit expense reports or review them.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS employees (
  employee_id                         TEXT                 PRIMARY KEY
);
ALTER TABLE employees ADD COLUMN IF NOT EXISTS first_name TEXT;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS last_name TEXT;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS email_address TEXT;                                  -- Used as the click-to-login identity.
